	}
}

// renderTreeCompact renders the knowledge tree in compact format for session start hook
func renderTreeCompact(root *KnowledgeNode, opts TreeOptions) (string, error) {
	// Filter clusters if SmellsOnly is set
	clustersWithSmells := []*KnowledgeNode{}
	totalClusters := 0

	for _, cluster := range root.Children {
		totalClusters++
		if opts.SmellsOnly {
			// Check if cluster has smells (for now, gracefully handle missing smells)
			if cluster.Metadata != nil {
				if smells, ok := cluster.Metadata["smells"].([]HealthSmell); ok && len(smells) > 0 {
					clustersWithSmells = append(clustersWithSmells, cluster)
				}
			}
		}
	}

	// If SmellsOnly mode and no smells found, return one-line summary
	if opts.SmellsOnly && len(clustersWithSmells) == 0 {
		return fmt.Sprintf("orch tree: %d clusters, no health smells\n", totalClusters), nil
	}

	// If SmellsOnly mode with smells, render only those clusters
	if opts.SmellsOnly && len(clustersWithSmells) > 0 {
		var sb strings.Builder
		sb.WriteString(fmt.Sprintf("orch tree: %d clusters with health smells:\n", len(clustersWithSmells)))
		for _, cluster := range clustersWithSmells {
			sb.WriteString(fmt.Sprintf("  • %s", cluster.Title))
			// Show smell badges
			if smells, ok := cluster.Metadata["smells"].([]HealthSmell); ok {
				for _, smell := range smells {
					sb.WriteString(fmt.Sprintf(" [%s]", getSmellBadge(smell.Type)))
				}
			}
			sb.WriteString("\n")
		}
		return sb.String(), nil
	}

	// Regular compact mode (no smells filter) - just cluster summary
	var sb strings.Builder
	sb.WriteString(fmt.Sprintf("orch tree: %d clusters\n", totalClusters))
	return sb.String(), nil
}

// renderWorkViewCompact renders the work view in compact format for session start hook
func renderWorkViewCompact(issues []*KnowledgeNode, opts TreeOptions) (string, error) {
	// Group issues by status
	statusGroups := make(map[NodeStatus][]*KnowledgeNode)
	for _, issue := range issues {
		statusGroups[issue.Status] = append(statusGroups[issue.Status], issue)
	}

	// Build compact summary
	var sb strings.Builder
	sb.WriteString("orch tree (work view):\n")

	statusOrder := []NodeStatus{StatusInProgress, StatusTriage, StatusOpen}
	for _, status := range statusOrder {
		group := statusGroups[status]
		if len(group) == 0 {
			continue
		}

		statusLabel := getCompactStatusLabel(status)
		sb.WriteString(fmt.Sprintf("  %s (%d)", statusLabel, len(group)))

		// Show first few IDs if compact
		if len(group) <= 3 {
			sb.WriteString(": ")
			for i, issue := range group {
				if i > 0 {
					sb.WriteString(", ")
				}
				sb.WriteString(issue.ID)
			}
		}
		sb.WriteString("\n")
	}

	return sb.String(), nil
}

// getCompactStatusLabel returns compact status labels for work view
func getCompactStatusLabel(status NodeStatus) string {
	switch status {
	case StatusInProgress:
		return "● Active"
	case StatusTriage:
		return "◇ Triage"
	case StatusOpen:
		return "◐ Ready"
	case StatusClosed:
		return "✓ Done"
	default:
		return string(status)
	}
}

// getSmellBadge returns a badge/icon for a health smell type
func getSmellBadge(smellType HealthSmellType) string {
	switch smellType {
	case SmellNeedsSynthesis:
		return "📚 needs synthesis"
	case SmellNotActedOn:
		return "⚠️ not acted on"
	case SmellUntestedModel:
		return "🧪 untested"
	default:
		return string(smellType)
	}
}

