// detectClusterHealthSmells detects health smells in a cluster
func detectClusterHealthSmells(cluster *Cluster) []HealthSmell {
	var smells []HealthSmell

	// Count different node types
	invCount := 0
	decisionCount := 0
	modelCount := 0
	probeCount := 0

	for _, node := range cluster.Nodes {
		switch node.Type {
		case NodeTypeInvestigation:
			invCount++
		case NodeTypeDecision:
			decisionCount++
		case NodeTypeModel:
			modelCount++
		case NodeTypeProbe:
			probeCount++
		}
	}

	// SmellNeedsSynthesis: 15+ investigations without decision/model
	if invCount >= 15 && decisionCount == 0 && modelCount == 0 {
		smells = append(smells, HealthSmell{
			Type:        SmellNeedsSynthesis,
			Description: fmt.Sprintf("%d investigations without synthesis", invCount),
			Count:       invCount,
		})
	}

	// SmellUntestedModel: Model without probes
	if modelCount > 0 && probeCount == 0 {
		smells = append(smells, HealthSmell{
			Type:        SmellUntestedModel,
			Description: fmt.Sprintf("%d model(s) without probes", modelCount),
			Count:       modelCount,
		})
	}

	// SmellNotActedOn: Decision without spawned issues
	// This would require querying beads for related issues, which is complex
	// For now, skip this smell detection (graceful degradation)

	return smells
}

